import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;

import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;

@Controller
@RequestMapping("/oauth2")
public class OAuth2ClientController {

    @Value("${oauth2.client.clientId}")
    private String clientId;

    @Value("${oauth2.client.redirectUri}")
    private String redirectUri;

    @Value("${oauth2.client.authorizationUri}")
    private String authorizationUri;

    @GetMapping("/authorize")
    public void redirectToAuthorizationServer(HttpServletResponse response) throws IOException {
        String scope = "read write";
        String responseType = "code";
        String authorizationUrl = createAuthorizationUrl(clientId, redirectUri, scope, responseType);
        response.sendRedirect(authorizationUrl);
    }

    private String createAuthorizationUrl(String clientId, String redirectUri, String scope, String responseType) {
        return authorizationUri + "?" +
                "client_id=" + URLEncoder.encode(clientId, StandardCharsets.UTF_8) + "&" +
                "redirect_uri=" + URLEncoder.encode(redirectUri, StandardCharsets.UTF_8) + "&" +
                "scope=" + URLEncoder.encode(scope, StandardCharsets.UTF_8) + "&" +
                "response_type=" + URLEncoder.encode(responseType, StandardCharsets.UTF_8);
    }
}

